import collections, re

# 1) ledger: md5prefix(10) -> (row, status, canonical-name)
ledger={}
for line in open('7z-cert-ledger.md'):
    m=re.match(r'\|\s*(\d+)\s*\|\s*([^|]+?)\s*\|\s*[^|]*\|\s*[^|]*\|\s*[^|]*\|\s*`([0-9a-f]{10})`', line)
    if m:
        row,status,md5=m.group(1),m.group(2).strip(),m.group(3)
        nm=re.search(r'`([^`]+\.7z[^`]*)`\s*(?:—|\|)?', line)
        ledger[md5]=(int(row),status, nm.group(1) if nm else '?')

# 2) local: path -> full md5 ; path -> strided ; strided -> set(md5prefix)
full={}
for line in open('fullhash_results.tsv'):
    p=line.rstrip('\n').split('\t')
    if len(p)==3: full[p[2]]=p[0]          # path -> md5(32)
strided={}
for line in open('strided.tsv'):
    p=line.rstrip('\n').split('\t')
    if len(p)==3: strided[p[2]]=p[1]        # path -> strided fp
sp_to_md5pref=collections.defaultdict(set)
for path,sp in strided.items():
    if not path.startswith('./bobbie/') and path in full:
        sp_to_md5pref[sp].add(full[path][:10])

# 3) bobbie files from inventory
bob=[]
for line in open('nas_inventory.tsv'):
    p=line.rstrip('\n').split('\t')
    if len(p)==3 and p[2].startswith('./bobbie/'): bob.append((int(p[0]),p[1],p[2]))

def verdict_class(status):
    if status.startswith('❌'): return 'FAIL'
    if 'OK (t)' in status: return 'OK(t)'
    if 'list-OK' in status or status.startswith('✅'): return 'list-OK'
    return status

summary=collections.Counter()
rows_hit=collections.Counter()
problems=[]
for s,b,p in bob:
    sp=strided.get(p)
    md5prefs = sp_to_md5pref.get(sp, set()) if sp else set()
    matched_rows=[ledger[mp] for mp in md5prefs if mp in ledger]
    if not matched_rows:
        summary['UNMATCHED']+=1; problems.append((s,b,p,'no local/ledger match')); continue
    # pick best verdict among matched (a bobbie file's strided may map to >1 divergent local md5)
    classes={verdict_class(st) for _,st,_ in matched_rows}
    best = 'OK(t)' if 'OK(t)' in classes else ('list-OK' if 'list-OK' in classes else 'FAIL')
    summary[best]+=1
    for rownum,_,_ in matched_rows: rows_hit[rownum]+=1
    if best=='FAIL':
        problems.append((s,b,p,f"only matches FAILED row(s) {[r for r,_,_ in matched_rows]}"))

print(f"BOBBIE files: {len(bob)}\n")
print("Doppelganger verdict for each bobbie file (via name+size+strided -> local -> ledger):")
for k in ['OK(t)','list-OK','FAIL','UNMATCHED']:
    if summary[k]: print(f"   {k:10s}: {summary[k]}")
print(f"\nDistinct ledger rows covered by bobbie files: {len(rows_hit)} / 27")
print(f"Rows NOT represented in bobbie: {sorted(set(range(1,28))-set(rows_hit))}")
if problems:
    print("\n--- bobbie files whose ONLY local doppelganger is a FAILED/UNMATCHED archive ---")
    for s,b,p,why in problems: print(f"   {s:>14,}  {b}  [{why}]")
else:
    print("\nNo bobbie file maps exclusively to a failed/unmatched local archive.")
